using System;using System.Collections.Generic;using System.Linq;class A{static int W,H,EX;static int[,]T,LK;static int[]DX={0,1,0,-1},DY={-1,0,1,0},OP={2,3,0,1};static int[][]RG={new[]{0},new[]{1},new[]{2,3},new[]{3,2},new[]{4,5},new[]{5,4},new[]{6,7,8,9},new[]{7,8,9,6},new[]{8,9,6,7},new[]{9,6,7,8},new[]{10,11,12,13},new[]{11,12,13,10},new[]{12,13,10,11},new[]{13,10,11,12}};static Dictionary<int,int>[]RM;static Dictionary<int,int>rot=new();static List<int[]>plan=new();static bool Dfs(int x,int y,int e){if(y>=H)return x==EX;if(x<0||x>=W||y<0)return false;int o=T[y,x],k=y*W+x;var cs=LK[y,x]==1?new[]{rot.GetValueOrDefault(k,o)}:RG[o];foreach(var c in cs){if(!RM[c].ContainsKey(e))continue;int ex=RM[c][e],nx=x+DX[ex],ny=y+DY[ex],ne=OP[ex];bool had=rot.ContainsKey(k);int pv=had?rot[k]:0;rot[k]=c;if(Dfs(nx,ny,ne)){if(c!=o)plan.Add(new[]{x,y,c});return true;}if(had)rot[k]=pv;else rot.Remove(k);}return false;}static void Main(){RM=new Dictionary<int,int>[14];for(int i=0;i<14;i++)RM[i]=new();RM[1][0]=2;RM[1][1]=2;RM[1][3]=2;RM[2][1]=3;RM[2][3]=1;RM[3][0]=2;RM[4][0]=3;RM[4][1]=2;RM[5][0]=1;RM[5][3]=2;RM[6][1]=3;RM[6][3]=1;RM[7][0]=2;RM[7][1]=2;RM[8][3]=2;RM[8][1]=2;RM[9][0]=2;RM[9][3]=2;RM[10][0]=3;RM[11][0]=1;RM[12][1]=2;RM[13][3]=2;var p=Console.ReadLine().Split();W=int.Parse(p[0]);H=int.Parse(p[1]);T=new int[H,W];LK=new int[H,W];for(int y=0;y<H;y++){p=Console.ReadLine().Split();for(int x=0;x<W;x++){int v=int.Parse(p[x]);T[y,x]=Math.Abs(v);LK[y,x]=v<0?1:0;}}EX=int.Parse(Console.ReadLine());var Q=new List<string>();var EM=new Dictionary<string,int>{{"TOP",0},{"RIGHT",1},{"LEFT",3}};for(;;){p=Console.ReadLine().Split();int xi=int.Parse(p[0]),yi=int.Parse(p[1]),ent=EM[p[2]];int R=int.Parse(Console.ReadLine());for(int i=0;i<R;i++)Console.ReadLine();if(!Q.Any()){rot.Clear();plan.Clear();if(Dfs(xi,yi,ent))foreach(var s in plan){int o=T[s[1],s[0]];var g=RG[o];int r=Array.IndexOf(g,s[2]);if(r<=0)continue;if(r<=2)for(int i=0;i<r;i++)Q.Add($"{s[0]} {s[1]} RIGHT");else Q.Add($"{s[0]} {s[1]} LEFT");T[s[1],s[0]]=s[2];}};Console.WriteLine(Q.Any()?Q[0]:"WAIT");if(Q.Any())Q.RemoveAt(0);}}}
